import{_ as t,c as e,o as l,V as o}from"./chunks/framework.35c8bad0.js";const x=JSON.parse('{"title":"面试题[Vue vs React]","description":"","frontmatter":{"title":"面试题[Vue vs React]","date":"2023-09-20T00:00:00.000Z"},"headers":[],"relativePath":"blog/interview/230920.md","lastUpdated":1778210567000}'),s={name:"blog/interview/230920.md"},r=o('<h1 id="面试题-vue-vs-react" tabindex="-1">面试题[Vue vs React] <a class="header-anchor" href="#面试题-vue-vs-react" aria-label="Permalink to &quot;面试题[Vue vs React]&quot;">​</a></h1><h2 id="_1-基础" tabindex="-1">1. 基础 <a class="header-anchor" href="#_1-基础" aria-label="Permalink to &quot;1. 基础&quot;">​</a></h2><h3 id="_1-1-核心思想-库-vs-框架" tabindex="-1">1.1 核心思想：库 vs 框架 <a class="header-anchor" href="#_1-1-核心思想-库-vs-框架" aria-label="Permalink to &quot;1.1 核心思想：库 vs 框架&quot;">​</a></h3><ul><li><strong>React</strong>：一个<strong>UI库</strong>，专注于构建用户界面。它本质上只是<strong>MVC 中的 View 层</strong>，其他能力（如路由、状态管理）需要从社区挑选第三方库（如 React Router、Redux）。</li><li><strong>Vue</strong>：一个<strong>渐进式框架</strong>。你可以只把它当 View 层用（核心库），也可以和官方提供的 Vue Router、Pinia 等全家桶整合成完整框架。</li></ul><h3 id="_1-2-模板语法-jsx-vs-template" tabindex="-1">1.2 模板语法：JSX vs Template <a class="header-anchor" href="#_1-2-模板语法-jsx-vs-template" aria-label="Permalink to &quot;1.2 模板语法：JSX vs Template&quot;">​</a></h3><ul><li><strong>React 使用 JSX</strong>：JSX 是 JavaScript 的语法扩展，允许你在 JS 中写 HTML 标签。它能力强大（原生 JS 控制流），但逻辑与结构耦合。</li><li><strong>Vue 使用 Template</strong>：基于 HTML 的模板语法，更接近传统 Web 开发（HTML/CSS/JS 分离）。Vue 编译器会在构建时优化模板，指令（v-for, v-if）封装了常见逻辑，更简洁但扩展性依赖指令。</li></ul><h3 id="_1-3-状态与数据更新" tabindex="-1">1.3 状态与数据更新 <a class="header-anchor" href="#_1-3-状态与数据更新" aria-label="Permalink to &quot;1.3 状态与数据更新&quot;">​</a></h3><ul><li><strong>React：不可变数据 + <code>setState</code></strong><ul><li>你必须用 <code>setState</code> 或 Hook 的 setter（如 <code>setCount</code>）来创建新对象。直接修改 <code>state</code> 不会触发重新渲染。</li><li>原因：React 依赖<strong>浅比较</strong>（<code>object.is</code>）来检测变化，需要新旧地址不同。</li></ul></li><li><strong>Vue：可变数据 + 响应式</strong><ul><li>Vue 用 <code>ref</code>/<code>reactive</code> 包装数据，通过 <code>Proxy</code> 代理属性。直接修改 <code>state.count++</code> 即可，Vue 会自动收集依赖并更新视图。</li><li>原因：Vue 在 <code>getter</code> 时收集依赖，在 <code>setter</code> 时通知更新。</li></ul></li></ul><h3 id="_1-4-性能优化-手动-vs-自动" tabindex="-1">1.4 性能优化：手动 vs 自动 <a class="header-anchor" href="#_1-4-性能优化-手动-vs-自动" aria-label="Permalink to &quot;1.4 性能优化：手动 vs 自动&quot;">​</a></h3><ul><li><strong>React</strong>：<strong>依赖手动优化</strong>。默认行为是“当组件状态变化，其<strong>整个子树</strong>都重新渲染”。你需要用 <code>React.memo</code>、<code>useMemo</code>、<code>useCallback</code> 来跳过不必要的子组件渲染。</li><li><strong>Vue</strong>：大多数情况下<strong>无需手动优化</strong>。响应式系统自动追踪依赖，只有依赖变化时该组件才重新渲染，粒度最小。</li></ul><h2 id="_2-进阶" tabindex="-1">2. 进阶 <a class="header-anchor" href="#_2-进阶" aria-label="Permalink to &quot;2. 进阶&quot;">​</a></h2><h3 id="_2-1-如何选择" tabindex="-1">2.1 如何选择 <a class="header-anchor" href="#_2-1-如何选择" aria-label="Permalink to &quot;2.1 如何选择&quot;">​</a></h3><p>在实际项目中，选择 Vue 还是 React 往往不是技术优劣的问题，而是<strong>匹配度</strong>的问题。以下是一套基于<strong>团队、项目、生态</strong>三个维度的决策框架，可以帮助你做出合理选择。</p><table><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">更适合 Vue 的情况</th><th style="text-align:left;">更适合 React 的情况</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>团队技术背景</strong></td><td style="text-align:left;">后端/全栈偏多、传统 Web 开发者、Vue 2 经验丰富</td><td style="text-align:left;">前端专业团队、习惯函数式编程、大量使用 TypeScript</td></tr><tr><td style="text-align:left;"><strong>项目类型</strong></td><td style="text-align:left;">快速迭代的管理系统、官网、中小型应用、需要渐进式接入</td><td style="text-align:left;">大型长周期应用、复杂交互、需要高度定制能力</td></tr><tr><td style="text-align:left;"><strong>生态需求</strong></td><td style="text-align:left;">移动端（Weex，但已不活跃）、桌面端（Electron 均可）</td><td style="text-align:left;">React Native（跨平台 App）、Remix/Next（全栈）</td></tr><tr><td style="text-align:left;"><strong>性能敏感度</strong></td><td style="text-align:left;">普通 CRUD 应用（两者持平）</td><td style="text-align:left;">超大列表/高频更新，需要精细控制渲染粒度</td></tr><tr><td style="text-align:left;"><strong>招聘与社区</strong></td><td style="text-align:left;">国内中小企业、外包项目常见</td><td style="text-align:left;">大厂、国际化项目、开源生态更活跃</td></tr><tr><td style="text-align:left;"><strong>开发体验偏好</strong></td><td style="text-align:left;">喜欢模板语法、声明式指令、直接修改数据</td><td style="text-align:left;">喜欢 JS 完全控制、推崇不可变性、喜欢写 JSX</td></tr></tbody></table><h3 id="_2-2-虚拟-dom-的区别" tabindex="-1">2.2 虚拟 DOM 的区别 <a class="header-anchor" href="#_2-2-虚拟-dom-的区别" aria-label="Permalink to &quot;2.2 虚拟 DOM 的区别&quot;">​</a></h3><table><thead><tr><th style="text-align:left;">对比维度</th><th style="text-align:left;"><strong>React</strong></th><th style="text-align:left;"><strong>Vue</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>核心理念</strong></td><td style="text-align:left;">&quot;我&#39;不知道&#39;哪里变了，所以全量比较，然后找出差异&quot;</td><td style="text-align:left;">&quot;我&#39;知道&#39;哪里变了，所以精准更新，并只做最小化比较&quot;</td></tr><tr><td style="text-align:left;"><strong>触发机制</strong></td><td style="text-align:left;">数据变化 (<code>setState</code>)，导致组件树<strong>自上而下全量</strong>重新渲染</td><td style="text-align:left;">响应式数据变化，通过 <code>Watcher</code> <strong>精准锁定</strong>发生变化的组件</td></tr><tr><td style="text-align:left;"><strong>Diff 比较起点</strong></td><td style="text-align:left;">从整棵虚拟 DOM 树的<strong>根节点</strong>开始</td><td style="text-align:left;">从发生变化的<strong>组件根节点</strong>开始</td></tr><tr><td style="text-align:left;"><strong>Diff 比较策略</strong></td><td style="text-align:left;"><strong>同层比较</strong>（基于假设优化，优先复用节点），子节点比较采用<strong>从左到右</strong>的双指针遍历</td><td style="text-align:left;">同样是<strong>同层比较</strong>，但子节点比较采用<strong>双端比较</strong>（同时从新旧列表两端开始），寻找更优复用方案</td></tr><tr><td style="text-align:left;"><strong>列表优化</strong></td><td style="text-align:left;"><strong>必须</strong>依靠 <code>key</code> 来识别元素，否则性能差且可能引发 bug</td><td style="text-align:left;"><strong>建议</strong>使用 <code>key</code>，但不是强制；内部会用<strong>最长递增子序列(LIS)</strong> 算法找出最小移动量</td></tr><tr><td style="text-align:left;"><strong>节点更新策略</strong></td><td style="text-align:left;"><strong>&quot;同类型则更新，否则销毁重建&quot;</strong>：只要元素类型相同，会尽量保留 DOM 节点，只更新变更的属性</td><td style="text-align:left;"><strong>&quot;更精确&quot;</strong>：会区分更多情况，更倾向于销毁并新建节点。例如，同元素但类名不同，Vue 认为不同并会重建</td></tr><tr><td style="text-align:left;"><strong>性能表现偏向</strong></td><td style="text-align:left;">在<strong>复杂的交互和动画逻辑</strong>中，其全量 Diff 策略可能更可控</td><td style="text-align:left;">在<strong>频繁数据更新</strong>的场景，其精准触发的机制理论上能带来更高性能</td></tr><tr><td style="text-align:left;"><strong>调度机制</strong></td><td style="text-align:left;">React 在处理虚拟 DOM 时使用了 Reconciliation 和 Fiber 架构，具有时间分片的特点</td><td style="text-align:left;">Vue 主要通过异步队列来批量更新，减少渲染次数</td></tr></tbody></table><p>两者虚拟 DOM 的差异，本质上是其底层设计哲学的体现：<strong>Vue 通过更精细的依赖收集来减少不必要的计算，倾向于“局部最优”；React 则秉持“简单可预测”的原则，倾向于“整体一致”</strong>。没有绝对的优劣，只有更适合特定场景的选择。</p>',17),a=[r];function n(d,g,i,c,f,u){return l(),e("div",null,a)}const y=t(s,[["render",n]]);export{x as __pageData,y as default};
